        else C[j] = max({C[j-1],tr[j],d[j]+sum[j]+mn});
        mn = max(mn,d[j]-sum[j]);
    }
    mn=-0x3f3f3f3f;
    for(int j=sz-1;j>=1;j--){
        if(j==sz-1) D[j] = max(tr[j+1],d[j+1]);
        else D[j] = max({D[j+1],tr[j+1],d[j+1]+sub[j+1]+mn});
